# Residual stream visualization in a mini-transformer
import torch
import torch.nn as nn

class ResidualStreamTransformer(nn.Module):
    """3-layer transformer; log residual stream norm at each step."""
    def __init__(self, d_model=256, n_heads=4, depth=3):
        super().__init__()
        self.embed = nn.Linear(16, d_model)
        self.blocks = nn.ModuleList([
            nn.ModuleDict({
                "attn": nn.MultiheadAttention(d_model, n_heads, batch_first=True),
                "ffn":  nn.Sequential(nn.Linear(d_model, d_model*4),
                                      nn.GELU(),
                                      nn.Linear(d_model*4, d_model)),
                "ln1":  nn.LayerNorm(d_model),
                "ln2":  nn.LayerNorm(d_model),
            })
            for _ in range(depth)
        ])
        self.head = nn.Linear(d_model, 1)

    def forward(self, x, verbose=False):
        x = self.embed(x)
        if verbose:
            print(f"After embed:   stream norm = {x.norm(dim=-1).mean():.3f}")
        for i, block in enumerate(self.blocks):
            attn_out, _ = block["attn"](x, x, x)
            x = block["ln1"](x + attn_out)          # residual + norm
            x = block["ln2"](x + block["ffn"](x))   # residual + norm
            if verbose:
                print(f"After block {i}: stream norm = {x.norm(dim=-1).mean():.3f}")
        return self.head(x.mean(dim=1))

model = ResidualStreamTransformer()
inp = torch.randn(2, 8, 16)   # (batch=2, seq=8, features=16)
_ = model(inp, verbose=True)
